import { OnboardingForm } from "@/registry/onboarding-kit/onboarding-form"

export default function OnboardingPage() {
  return (
    <div className="h-svh">
      <OnboardingForm />
    </div>
  )
}

"use client";

import { useState } from "react";
import { Survey } from "@/components/survey";
import type { QuestionConfig } from "@/components/survey";

interface Attrs {
  name?: string;
  role?: string;
  goal?: string;
}

const steps: QuestionConfig<Attrs>[] = [
  {
    id: "name",
    title: "What's your name?",
    type: "text",
    placeholder: "Jane Doe",
  },
  {
    id: "role",
    title: "What's your role?",
    type: "radio",
    variant: "button",
    options: [
      { value: "engineer", label: "Engineer" },
      { value: "designer", label: "Designer" },
      { value: "pm", label: "Product Manager" },
      { value: "founder", label: "Founder" },
    ],
  },
  {
    id: "goal",
    title: "What are you building?",
    type: "textarea",
    placeholder: "Tell us about your project...",
  },
];

export function OnboardingForm() {
  const [attrs, setAttrs] = useState<Attrs>({});
  const [done, setDone] = useState(false);

  if (done) {
    return (
      <div className="flex h-svh items-center justify-center p-8">
        <div className="w-full max-w-lg text-center">
          <h1 className="text-2xl font-bold">Welcome, {attrs.name}!</h1>
          <p className="mt-2 text-muted-foreground">Onboarding complete.</p>
          <pre className="mt-4 overflow-auto rounded bg-muted p-4 text-left text-sm">
            {JSON.stringify(attrs, null, 2)}
          </pre>
        </div>
      </div>
    );
  }

  return (
    <Survey
      questions={steps}
      attributes={attrs}
      onAttributeChange={setAttrs}
      onComplete={(final) => {
        setAttrs(final);
        setDone(true);
      }}
      showProgress
      logo={<span className="text-lg font-bold tracking-tight">My App</span>}
    />
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { z } from "zod";
import { AlertCircle, ArrowLeft } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";
import { SurveyShell, SurveyQuestion } from "./survey-shell";
import { QuestionRenderer } from "./question-renderer";
import { useCurrentQuestion } from "./hooks/use-current-question";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import type { QuestionConfig } from "./types";

export interface SurveyProps<A extends Record<string, any>> {
  questions: QuestionConfig<A>[];
  attributes: A;
  onAttributeChange: (attributes: A) => void;
  onComplete: (attributes: A) => void;
  /** Custom right panel content. Overrides `rightImage`. */
  rightContent?: React.ReactNode;
  /** Shorthand: provide an image URL and it fills the right panel as cover. */
  rightImage?: string;
  /** Hide the right panel and center the survey content. */
  hideRightPanel?: boolean;
  /** Logo image URL for top-left branding. Max height 32px. */
  logoUrl?: string;
  /** Custom logo element (overrides `logoUrl`). */
  logo?: React.ReactNode;
  onBackFromFirstQuestion?: () => void;
  hideContinueButton?: boolean;
  hideQuestionTitle?: boolean;
  showProgress?: boolean;
  className?: string;
}

export function Survey<A extends Record<string, any>>({
  questions,
  attributes,
  onAttributeChange,
  onComplete,
  rightContent,
  rightImage,
  hideRightPanel = false,
  logoUrl,
  logo,
  onBackFromFirstQuestion,
  hideContinueButton = false,
  hideQuestionTitle = false,
  showProgress = false,
  className,
}: SurveyProps<A>) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [tempAnswer, setTempAnswer] = useState<any>(null);
  const [validationError, setValidationError] = useState("");

  const {
    filteredQuestions,
    currentQuestion,
    currentQuestionIndex,
    setActiveQuestionId,
    totalQuestions,
  } = useCurrentQuestion(questions, attributes);

  useEffect(() => {
    if (currentQuestion) {
      const existing = (attributes as any)[currentQuestion.id];
      if (currentQuestion.type === "info") {
        setTempAnswer(true);
      } else if (currentQuestion.type === "slider" && existing === undefined) {
        const sp = currentQuestion.sliderProps;
        const min = sp?.min ?? 0;
        const max = sp?.max ?? 10;
        setTempAnswer(Math.round((min + max) / 2));
      } else {
        setTempAnswer(existing);
      }
      setValidationError("");
    }
  }, [currentQuestion, attributes]);

  const validate = (): boolean => {
    if (!currentQuestion?.validationSchema) return true;
    try {
      currentQuestion.validationSchema.parse(tempAnswer);
      setValidationError("");
      return true;
    } catch (err) {
      if (err instanceof z.ZodError) {
        setValidationError(
          currentQuestion.validationErrorMessage ??
            err.issues[0]?.message ??
            "Invalid input"
        );
      }
      return false;
    }
  };

  const goToNext = () => {
    if (!validate()) return;
    if (currentQuestion) {
      const next = { ...attributes, [currentQuestion.id]: tempAnswer };
      onAttributeChange(next);
    }
    if (
      currentQuestionIndex !== -1 &&
      currentQuestionIndex < filteredQuestions.length - 1
    ) {
      const nextQ = filteredQuestions[currentQuestionIndex + 1];
      if (nextQ) setActiveQuestionId(String(nextQ.id));
    } else {
      handleComplete();
    }
  };

  const goToPrevious = () => {
    setValidationError("");
    if (currentQuestionIndex === 0 && onBackFromFirstQuestion) {
      onBackFromFirstQuestion();
    } else if (currentQuestionIndex > 0) {
      const prevQ = filteredQuestions[currentQuestionIndex - 1];
      if (prevQ) setActiveQuestionId(String(prevQ.id));
    }
  };

  const handleComplete = () => {
    if (!validate()) return;
    if (currentQuestion) {
      onComplete({ ...attributes, [currentQuestion.id]: tempAnswer });
    } else {
      onComplete(attributes);
    }
  };

  // Resolve right panel: hidden > explicit content > image shorthand > default gradient
  const resolvedRightContent = hideRightPanel
    ? undefined
    : rightContent ?? (rightImage ? (
        <div className="relative h-full w-full overflow-hidden rounded-2xl">
          <img
            src={rightImage}
            alt=""
            className="size-full object-cover"
          />
          <div className="absolute inset-0 rounded-2xl ring-1 ring-inset ring-foreground/5" />
        </div>
      ) : (
        <div className="relative h-full w-full overflow-hidden rounded-2xl bg-gradient-to-tr from-primary via-primary to-primary/80">
          <div className="absolute inset-0 rounded-2xl ring-1 ring-inset ring-foreground/5" />
        </div>
      ));

  if (!currentQuestion) return null;

  const showBack = currentQuestionIndex > 0 || !!onBackFromFirstQuestion;
  const showNext = !hideContinueButton && (currentQuestion.type === "info" || !!tempAnswer);
  const progressPercent =
    currentQuestionIndex >= 0 && totalQuestions
      ? ((currentQuestionIndex + 1) / totalQuestions) * 100
      : 0;

  return (
    <SurveyShell
      className={className}
      rightContent={resolvedRightContent}
      logo={logo}
      logoUrl={logoUrl}
      showProgress={showProgress}
      progressPercent={progressPercent}
      actions={
        <div className="mx-auto w-full max-w-lg">
          {/* Desktop */}
          <div className="hidden items-center justify-between md:flex">
            <Button variant="outline" size="icon" className={cn("min-h-10 min-w-10", showBack ? "" : "invisible")} onClick={goToPrevious} aria-label="Go back">
              <ArrowLeft />
            </Button>
            <Button size="lg" onClick={goToNext} className={showNext ? "" : "invisible"}>
              Continue
            </Button>
          </div>
          {/* Mobile */}
          {!hideContinueButton && (
            <div className="flex gap-3 md:hidden">
              {showBack && (
                <Button variant="outline" size="lg" className="flex-1" onClick={goToPrevious} aria-label="Go back">
                  <ArrowLeft />
                  Back
                </Button>
              )}
              <Button size="lg" className="flex-1" onClick={goToNext} disabled={!showNext}>
                Continue
              </Button>
            </div>
          )}
        </div>
      }
    >
      <div ref={containerRef} className="mx-auto w-full max-w-lg py-6">
        {/* Question — fade + subtle slide on transition */}
        <AnimatePresence mode="wait" initial={false}>
          <motion.div
            key={currentQuestion.id}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -4 }}
            transition={{ duration: 0.25, ease: [0.2, 0, 0, 1] }}
          >
            <SurveyQuestion
              title={currentQuestion.title}
              description={currentQuestion.description}
              active
              hideQuestionTitle={hideQuestionTitle}
            >
              <QuestionRenderer
                question={currentQuestion}
                attributes={attributes}
                isActive
                onEnter={goToNext}
                onChange={(value: any) => {
                  setTempAnswer(value);
                  setValidationError("");
                }}
                value={tempAnswer}
              />
              {validationError && (
                <Alert variant="destructive" className="mt-4">
                  <AlertCircle />
                  <AlertDescription>{validationError}</AlertDescription>
                </Alert>
              )}
            </SurveyQuestion>
          </motion.div>
        </AnimatePresence>
      </div>
    </SurveyShell>
  );
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";
import { Progress } from "@/components/ui/progress";

/* ---------------------------------- Types --------------------------------- */

export interface SurveyShellProps extends React.HTMLAttributes<HTMLDivElement> {
  children?: React.ReactNode;
  rightContent?: React.ReactNode;
  logoUrl?: string;
  logo?: React.ReactNode;
  showProgress?: boolean;
  progressPercent?: number;
  actions?: React.ReactNode;
}

/* -------------------------------- Component ------------------------------- */

const SurveyShell = React.forwardRef<HTMLDivElement, SurveyShellProps>(
  ({ className, children, rightContent, logoUrl, logo, showProgress, progressPercent, actions, ...props }, ref) => {
    const resolvedLogo = logo ?? (logoUrl ? (
      <img src={logoUrl} alt="Logo" className="max-h-8 w-auto" />
    ) : null);

    const hasHeader = resolvedLogo || (showProgress && progressPercent !== undefined);

    return (
      <div
        ref={ref}
        className={cn("flex h-full w-full", className)}
        {...props}
      >
        {/*
          Left panel — single overflow-y-auto container.
          Scrollbar sits at the right edge (between left and right panels).
          Header and actions use sticky positioning within the scroll flow.
          Pattern from Diino's StickToBottom + StickyChatContainer.
        */}
        <div
          className={cn(
            "relative h-full overflow-y-auto",
            rightContent ? "w-full md:w-1/2" : "mx-auto w-full max-w-2xl"
          )}
        >
          <div className="flex min-h-full flex-col">
            {/* Header — sticky top */}
            {hasHeader && (
              <div className="sticky top-0 z-20 bg-inherit px-8 pt-6 pb-3 md:px-12 md:pt-8">
                <div className="mx-auto w-full max-w-lg">
                  {resolvedLogo}
                  {showProgress && progressPercent !== undefined && (
                    <Progress value={progressPercent} className="mt-2 h-1.5 w-24" />
                  )}
                </div>
              </div>
            )}

            {/* Content — flex-1 + justify-end pushes content to bottom like Diino's chat feed */}
            <div className="flex min-h-0 flex-1 flex-col justify-end px-8 md:px-12">
              {children}
            </div>

            {/* Actions — sticky bottom (like StickyChatContainer) */}
            {actions && (
              <div className="sticky bottom-0 z-20 bg-inherit px-8 pb-6 pt-4 md:px-12 md:pb-8">
                {actions}
              </div>
            )}
          </div>
        </div>

        {/* Right panel — static, no scroll */}
        {rightContent && (
          <div className="sticky top-0 hidden max-h-dvh shrink-0 md:flex md:w-1/2 md:p-4">
            {rightContent}
          </div>
        )}
      </div>
    );
  }
);
SurveyShell.displayName = "SurveyShell";

/* ------------------------------ Sub-components ----------------------------- */

export interface SurveyQuestionProps
  extends React.HTMLAttributes<HTMLDivElement> {
  title: string;
  description?: string;
  children: React.ReactNode;
  active?: boolean;
  hideQuestionTitle?: boolean;
}

const SurveyQuestion = React.forwardRef<HTMLDivElement, SurveyQuestionProps>(
  (
    {
      className,
      title,
      description,
      children,
      active = true,
      hideQuestionTitle,
      ...props
    },
    ref
  ) => (
    <div
      ref={ref}
      className={cn("w-full", !active && "opacity-60", className)}
      {...props}
    >
      {!hideQuestionTitle && (
        <h2 className={cn("max-w-lg text-2xl font-semibold tracking-tight text-foreground md:text-3xl", !description && "mb-6")}>
          {title}
        </h2>
      )}
      {description && (
        <p className="mt-3 mb-6 max-w-lg leading-relaxed text-muted-foreground">
          {description}
        </p>
      )}
      <div className={cn(!active && "pointer-events-none")}>{children}</div>
    </div>
  )
);
SurveyQuestion.displayName = "SurveyQuestion";

const SurveyRightPanel = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, children, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex h-full w-full items-center justify-center", className)}
    {...props}
  >
    {children}
  </div>
));
SurveyRightPanel.displayName = "SurveyRightPanel";

export { SurveyShell, SurveyQuestion, SurveyRightPanel };

"use client";

import { TextInputQuestion } from "./text-input-question";
import { TextareaQuestion } from "./textarea-question";
import { RadioQuestion } from "./radio-question";
import { CardCheckboxQuestion } from "./card-checkbox-question";
import { SliderQuestion } from "./slider-question";
import { RatingQuestion } from "./rating-question";
import type { QuestionConfig, CardOption } from "./types";
import { useQuestionOptions } from "./hooks/use-question-options";

interface QuestionRendererProps<A = any> {
  question: QuestionConfig<A>;
  attributes: A;
  isActive: boolean;
  onEnter?: () => void;
  onChange: (value: any) => void;
  value: any;
}

export function QuestionRenderer<A>({
  question,
  attributes,
  isActive,
  onEnter,
  onChange,
  value,
}: QuestionRendererProps<A>) {
  const { options, error } = useQuestionOptions(question, attributes);

  if (error) {
    return (
      <div className="py-4 text-destructive">
        <p>Error loading options: {error}</p>
      </div>
    );
  }

  switch (question.type) {
    case "info":
      return null;

    case "text":
      return (
        <TextInputQuestion
          id={question.id}
          value={(value as string) ?? ""}
          onChange={onChange}
          onEnter={isActive ? onEnter : undefined}
          disabled={!isActive}
          placeholder={question.placeholder}
          placeholders={question.placeholders}
        />
      );

    case "number":
      return (
        <TextInputQuestion
          id={question.id}
          value={value?.toString() ?? ""}
          onChange={(val) => onChange(val ? parseInt(val, 10) : undefined)}
          onEnter={isActive ? onEnter : undefined}
          disabled={!isActive}
          type="number"
          min={18}
          max={120}
        />
      );

    case "radio":
      return (
        <RadioQuestion
          id={question.id}
          options={options.map((opt) => ({
            ...opt,
            value: String(opt.value),
          }))}
          value={(value as string) ?? ""}
          onChange={onChange}
          onAutoAdvance={isActive ? onEnter : undefined}
          disabled={!isActive}
          variant={question.variant}
        />
      );

    case "boolean":
      return (
        <RadioQuestion
          id={question.id}
          options={[
            { value: "true", label: "Yes" },
            { value: "false", label: "No" },
          ]}
          value={value === true ? "true" : value === false ? "false" : ""}
          onChange={(val: string) => onChange(val === "true")}
          onAutoAdvance={isActive ? onEnter : undefined}
          disabled={!isActive}
        />
      );

    case "card-checkbox": {
      const isSingle = question.cardCheckboxProps?.singleSelection;
      return (
        <CardCheckboxQuestion
          id={question.id}
          options={options as CardOption[]}
          values={
            isSingle ? (value ? [value as string] : []) : Array.isArray(value) ? value : []
          }
          onChange={(values: string[]) => {
            if (isSingle) {
              onChange(values.length > 0 ? values[values.length - 1] : undefined);
            } else {
              onChange(values);
            }
          }}
          disabled={!isActive}
        />
      );
    }

    case "textarea":
      return (
        <TextareaQuestion
          id={question.id}
          value={(value as string) ?? ""}
          onChange={onChange}
          disabled={!isActive}
          placeholder={question.placeholder}
        />
      );

    case "slider": {
      const sp = question.sliderProps;
      return (
        <SliderQuestion
          id={question.id}
          value={value as number | undefined}
          onChange={onChange}
          min={sp?.min}
          max={sp?.max}
          step={sp?.step}
          minLabel={sp?.minLabel}
          maxLabel={sp?.maxLabel}
          disabled={!isActive}
        />
      );
    }

    case "rating":
      return (
        <RatingQuestion
          id={question.id}
          value={value as number | undefined}
          onChange={onChange}
          max={question.ratingProps?.max}
          disabled={!isActive}
          onAutoAdvance={isActive ? onEnter : undefined}
        />
      );

    default:
      return (
        <div className="text-muted-foreground">
          Unsupported question type: {question.type}
        </div>
      );
  }
}

"use client";

import { useState, type KeyboardEvent, useEffect, useRef } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";
import { CheckIndicator } from "./check-indicator";
import {
  AUTO_ADVANCE_CONFIG,
  PROGRESS_BAR_ANIMATION,
} from "./auto-advance-config";
interface RadioOption {
  value: string;
  label: string;
  emoji?: string;
  icon?: React.ComponentType<{ className?: string }>;
  description?: string;
}

interface RadioQuestionProps {
  id?: string;
  options: RadioOption[];
  value: string;
  onChange: (value: string) => void;
  className?: string;
  onAutoAdvance?: () => void;
  disabled?: boolean;
  variant?: "button" | "card";
}

export function RadioQuestion({
  options,
  value,
  onChange,
  className,
  onAutoAdvance,
  disabled = false,
  variant = "button",
}: RadioQuestionProps) {
  const [animatingValue, setAnimatingValue] = useState<string | null>(null);

  const onAutoAdvanceRef = useRef(onAutoAdvance);
  useEffect(() => {
    onAutoAdvanceRef.current = onAutoAdvance;
  }, [onAutoAdvance]);

  const handleSelect = (optionValue: string) => {
    if (disabled) return;

    onChange(optionValue);
    setAnimatingValue(optionValue);

    if (onAutoAdvanceRef.current) {
      setTimeout(() => {
        setAnimatingValue(null);
        onAutoAdvanceRef.current?.();
      }, AUTO_ADVANCE_CONFIG.TOTAL_DELAY);
    } else {
      setTimeout(() => {
        setAnimatingValue(null);
      }, AUTO_ADVANCE_CONFIG.ANIMATION_DURATION);
    }
  };

  const handleKeyDown = (e: KeyboardEvent, optionValue: string) => {
    if (disabled) return;
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      handleSelect(optionValue);
    }
  };

  /* ─── Card variant ─────────────────────────────────────────────────── */
  if (variant === "card") {
    return (
      <div
        role="radiogroup"
        className={cn(
          "grid grid-cols-2 gap-4",
          className
        )}
      >
        {options.map((option) => {
          const isSelected = value === option.value;
          const isAnimating = animatingValue === option.value;
          return (
            <motion.div
              key={option.value}
              whileTap={disabled ? {} : { scale: 0.96 }}
              className={cn(
                "group relative flex cursor-pointer flex-col items-center justify-center overflow-hidden rounded-xl p-6 ring-1 transition-[box-shadow,ring-color]",
                "min-h-[160px]",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                isSelected
                  ? "ring-primary shadow-sm"
                  : "ring-border hover:ring-primary/40 shadow-[0_1px_2px_0_rgb(0_0_0/0.04)]",
                disabled && "cursor-not-allowed opacity-60"
              )}
              onClick={() => handleSelect(option.value)}
              onKeyDown={(e) => handleKeyDown(e, option.value)}
              tabIndex={disabled ? -1 : 0}
              role="radio"
              aria-checked={isSelected}
            >
              {/* Progress sweep — fills left to right on selection */}
              {isAnimating && !disabled && (
                <motion.div
                  className="absolute inset-0 z-0 origin-left bg-primary/5 will-change-transform"
                  initial={{ scaleX: 0 }}
                  animate={{ scaleX: 1 }}
                  transition={{ duration: 0.8, ease: "linear" }}
                />
              )}

              <CheckIndicator selected={isSelected} className="absolute right-3 top-3 z-10" />

              {/* Icon / Emoji */}
              <div className="relative z-10 mb-4 flex items-center justify-center">
                {option.icon ? (
                  <option.icon className="size-12 shrink-0 text-muted-foreground" />
                ) : option.emoji ? (
                  <span className="shrink-0 text-5xl">{option.emoji}</span>
                ) : null}
              </div>

              {/* Label */}
              <div className="relative z-10 flex flex-col items-center gap-1 text-center">
                <span className="font-medium">{option.label}</span>
                {option.description && (
                  <span className="text-sm leading-snug text-muted-foreground">
                    {option.description}
                  </span>
                )}
              </div>
            </motion.div>
          );
        })}
      </div>
    );
  }

  /* ─── Button variant (default) ─────────────────────────────────────── */
  return (
    <div
      role="radiogroup"
      className={cn("flex flex-col gap-3", className)}
    >
      {options.map((option) => {
        const isSelected = value === option.value;
        const isAnimating = animatingValue === option.value;
        return (
          <motion.div
            key={option.value}
            whileTap={disabled ? {} : { scale: 0.96 }}
            className={cn(
              "group relative flex w-full cursor-pointer items-center justify-between overflow-hidden rounded-lg px-3 text-base ring-1 transition-[box-shadow,ring-color]",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
              option.description ? "min-h-[60px] py-2.5" : "h-[50px]",
              isSelected
                ? "ring-primary shadow-sm"
                : "ring-border bg-card hover:ring-primary/40 shadow-[0_1px_2px_0_rgb(0_0_0/0.04)]",
              disabled && "cursor-not-allowed opacity-60"
            )}
            onClick={() => handleSelect(option.value)}
            onKeyDown={(e) => handleKeyDown(e, option.value)}
            tabIndex={disabled ? -1 : 0}
            role="radio"
            aria-checked={isSelected}
          >
            {/* Progress sweep — fills left to right on selection */}
            {isAnimating && !disabled && (
              <motion.div
                className="absolute inset-0 z-0 origin-left bg-primary/5 will-change-transform"
                initial={{ scaleX: 0 }}
                animate={{ scaleX: 1 }}
                transition={{ duration: 0.8, ease: "linear" }}
              />
            )}

            <div
              className={cn(
                "relative z-10 flex items-center gap-3",
                option.description ? "items-start" : "items-center"
              )}
            >
              {option.icon ? (
                <option.icon className="size-4 shrink-0 self-center text-muted-foreground" />
              ) : option.emoji ? (
                <span className="shrink-0 self-center text-xl">
                  {option.emoji}
                </span>
              ) : null}
              <span className="flex flex-col gap-1">
                <span className="font-medium">{option.label}</span>
                {option.description && (
                  <span className="text-sm leading-snug text-muted-foreground">
                    {option.description}
                  </span>
                )}
              </span>
            </div>

            <CheckIndicator selected={isSelected} className="relative z-10" />
          </motion.div>
        );
      })}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { Card, CardContent } from "@/components/ui/card";
import { CheckIndicator } from "./check-indicator";

interface CardOption {
  value: string;
  label: string;
  description?: string;
  imageUrl?: string;
}

interface CardCheckboxQuestionProps {
  id?: string;
  options: CardOption[];
  values: string[];
  onChange: (values: string[]) => void;
  className?: string;
  columns?: 1 | 2;
  disabled?: boolean;
}

export function CardCheckboxQuestion({
  options,
  values,
  onChange,
  className,
  columns = 2,
  disabled = false,
}: CardCheckboxQuestionProps) {
  const toggleOption = (optionValue: string) => {
    if (disabled) return;
    if (values.includes(optionValue)) {
      onChange(values.filter((v) => v !== optionValue));
    } else {
      onChange([...values, optionValue]);
    }
  };

  return (
    <div
      className={cn(
        "grid gap-4",
        columns === 1 ? "grid-cols-1" : "grid-cols-2",
        className,
      )}
    >
      {options.map((option) => {
        const isSelected = values.includes(option.value);
        return (
          <Card
            key={option.value}
            className={cn(
              "group relative cursor-pointer transition-[box-shadow,ring-color] active:scale-[0.96]",
              isSelected
                ? "ring-2 ring-primary"
                : "hover:ring-1 hover:ring-primary/40",
              disabled && "cursor-not-allowed opacity-60"
            )}
            onClick={() => toggleOption(option.value)}
            tabIndex={disabled ? -1 : 0}
            role="checkbox"
            aria-checked={isSelected}
            onKeyDown={(e) => {
              if (e.key === "Enter" || e.key === " ") {
                e.preventDefault();
                toggleOption(option.value);
              }
            }}
          >
            {option.imageUrl && (
              <img
                src={option.imageUrl}
                alt={option.label}
                className="aspect-square w-full object-cover"
              />
            )}
            <CardContent>
              <div className="text-base font-medium text-foreground">
                {option.label}
              </div>
              {option.description && (
                <div className="mt-1 text-sm text-muted-foreground">
                  {option.description}
                </div>
              )}
            </CardContent>

            <CheckIndicator selected={isSelected} className="absolute right-3 top-3" />
          </Card>
        );
      })}
    </div>
  );
}

