import { useMemo, useCallback, useState } from "react";
import type { QuestionConfig } from "../types";

/**
 * Manages which question is currently active.
 * Pure state-based — no router dependency. Drop into any framework.
 */
export function useCurrentQuestion<A = any>(
  questions: QuestionConfig<A>[],
  attributes: A,
  initialQuestionId?: string
) {
  const [activeId, setActiveId] = useState<string | null>(
    initialQuestionId ?? null
  );

  // Filter questions whose conditions are met.
  const filteredQuestions = useMemo(
    () =>
      questions.filter((q) => {
        if (!q.condition) return true;
        return q.condition(attributes);
      }),
    [questions, attributes]
  );

  // Auto-select first question if none is active.
  const effectiveId = useMemo(() => {
    if (activeId && filteredQuestions.some((q) => String(q.id) === activeId)) {
      return activeId;
    }
    return filteredQuestions.length > 0 ? String(filteredQuestions[0].id) : null;
  }, [activeId, filteredQuestions]);

  const currentQuestion = useMemo(
    () => filteredQuestions.find((q) => String(q.id) === effectiveId),
    [filteredQuestions, effectiveId]
  );

  const currentQuestionIndex = useMemo(
    () => filteredQuestions.findIndex((q) => String(q.id) === effectiveId),
    [filteredQuestions, effectiveId]
  );

  const setActiveQuestionId = useCallback((id: string | null) => {
    setActiveId(id);
  }, []);

  return {
    filteredQuestions,
    currentQuestion,
    currentQuestionIndex,
    activeQuestionId: effectiveId,
    setActiveQuestionId,
    totalQuestions: filteredQuestions.length,
  };
}

import { useMemo } from "react";
import type {
  QuestionConfig,
  OptionsLoadingState,
  BaseOption,
  SyncOptionsFunction,
} from "../types";

export function useQuestionOptions<T extends BaseOption, A = any>(
  question: QuestionConfig<A>,
  attributes: A
): OptionsLoadingState<T> {
  const options = useMemo(() => {
    if (!question.options) return [];

    if (Array.isArray(question.options)) {
      return question.options as T[];
    }

    const syncFn = question.options as SyncOptionsFunction<T, A>;
    return syncFn(attributes);
  }, [question.options, attributes]);

  return { options, loading: false, error: null };
}

import { useMemo } from "react";
import type { QuestionConfig } from "../types";

export interface QuestionState {
  isOptional: boolean;
  isAnswered: boolean;
}

export function useQuestionState<A = any>(
  currentQuestion: QuestionConfig<A> | undefined,
  attributes: A
): QuestionState {
  const isOptional = currentQuestion?.optional === true;

  const isAnswered = useMemo(() => {
    if (!currentQuestion) return false;
    const value = (attributes as any)[currentQuestion.id];

    switch (currentQuestion.type) {
      case "text":
        return typeof value === "string" && value.trim() !== "";
      case "number":
        return typeof value === "number" && !isNaN(value);
      case "radio":
      case "boolean":
        return value !== undefined && value !== "";
      case "card-checkbox":
        if (currentQuestion.cardCheckboxProps?.singleSelection) {
          return typeof value === "string" && value !== "";
        }
        return Array.isArray(value) && value.length > 0;
      default:
        return false;
    }
  }, [currentQuestion, attributes]);

  return { isOptional, isAnswered };
}
